import React from 'react';
import { Gradient } from './background.js';

function GradientCanvas() {
  const [gradientInstance, setGradientInstance] = React.useState(null);

  React.useEffect(() => {
    // Check if the device can handle the gradient
    const isDeviceCapable = checkDeviceCapabilities();

    // Create the gradient instance if the device is capable
    if (isDeviceCapable) {
      const gradient = new Gradient();
      gradient.initGradient('#gradient-canvas');
      setGradientInstance(gradient);
    }
  }, []);

  // Pause the gradient instance if it exists
  React.useEffect(() => {
    if (gradientInstance) {
      gradientInstance.pause();
    }
  }, [gradientInstance]);

  // Check device capabilities (example implementation, customize as needed)
  const checkDeviceCapabilities = () => {
    // You can use feature detection or device capabilities API to determine if the device can handle the gradient.
    // For example, you can check the device's CPU, memory, or graphics capabilities.
    // Here's a basic example that assumes devices with less than 2GB of RAM can't handle the gradient:
    const deviceMemory = navigator.deviceMemory;
    return deviceMemory >= 2; // Adjust the threshold as needed
  };

  return (
    <canvas id="gradient-canvas" data-js-darken-top data-transition-in />
  );
}

export default GradientCanvas;
